      this.axesHelper.position.x = this.person.position.x;
      this.axesHelper.position.y = this.person.position.y;
      this.axesHelper.position.z = this.person.position.z;

      // 网格物体始终面对场景中的相机
      this.person.lookAt(this.mainCamera.position);

      this.orbit.target = this.person.position;
      this.orbit.update();
      this.renderer.render(this.scene, this.mainCamera);
