    // 初始化渲染器
    initRenderer: function () {
      /**
       * 实例化透视相机
       * 为了避免边缘变形，这里将fov角度设置小一些，距离拉远一些
       * 固定视域角度，求需要多少距离才能满足完整的视野画面
       * 15度等于(Math.PI / 12)
       *
       * fov：摄像机视锥体垂直视野角度，从视图的底部到顶部，以角度来表示。默认值是50。
       * aspect：摄像机视锥体的长宽比，通常是使用画布的宽/画布的高。默认值是1（正方形画布）。
       * near：摄像机的近端面，默认值是0.1。
       * far：摄像机的远端面，默认值是2000。
       */
      const depth = 1400;
      const fov = 15;
      const aspect = this.windowSizes.width / this.windowSizes.height;
      const near = 0.1;
      const far = 2000;
      const distance = this.windowSizes.width / 2 / Math.tan(Math.PI / 12);
      const zAxisNumber = Math.floor(distance - depth / 2);

      this.mainCamera = new THREE.PerspectiveCamera(fov, aspect, near, far);
      this.mainCamera.position.set(0, 0, zAxisNumber);
      this.mainCamera.lookAt(0, 0, 0);
      this.mainCamera.position.y = 100;
      this.mainCamera.position.z = 150;

      this.scene.add(this.mainCamera);

      this.scene.add(new THREE.GridHelper(100, 10, 0x888888, 0x444444));

      const light = new THREE.AmbientLight(0xffffff, 2);
      light.position.set(1, 1, 1);
      this.scene.add(light);

      this.renderer = new THREE.WebGLRenderer({
        canvas: this.$refs.mainCanvas
      });
      this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
      this.renderer.setSize(this.windowSizes.width, this.windowSizes.height);

      // OrbitControls（轨道控制器）可以使得相机围绕目标进行轨道运动。
      this.orbit = new OrbitControls(this.mainCamera, this.renderer.domElement);

