    addClickListener: function () {
      document.addEventListener("click", (event) => {
        let pointer = new THREE.Vector2();
        // 将鼠标位置归一化为设备坐标。x 和 y 方向的取值范围是 (-1 to +1)
        pointer.x = (event.clientX / this.windowSizes.width) * 2 - 1;
        pointer.y = -(event.clientY / this.windowSizes.height) * 2 + 1;
        let raycaster = new THREE.Raycaster();
        // 通过摄像机和鼠标位置更新射线
        raycaster.setFromCamera(pointer, this.mainCamera);
        // 计算物体和射线的焦点
        // geometries为需要监听的Mesh合集，可以通过这个集合来过滤掉不需要监听的元素例如地面天空
        // true为不拾取子对象
        // intersects几何体合集
        let intersects = raycaster.intersectObjects(this.graphSpace.meshGroups, true);
        // 被射线穿过的几何体为一个集合，越排在前面说明其位置离端点越近，所以直接取[0]
        if (intersects.length > 0) {
          this.controls.attach(intersects[0].object);
        } else {
          // 若没有几何体被监听到，可以做一些取消操作
        }
      });
    },
    keyBroadcast: function () {
      if (!this.isKeyBroadcast) {
        return;
      }

      const delta = this.clock.getDelta();
      // 移动速度
      const moveDistance = 50 * delta;
      // P
      if (this.keyboard.pressed("p")) {
        this.controls.setMode("translate");
      }
      // O
      if (this.keyboard.pressed("o")) {
        this.controls.setMode("rotate");
      }
      // I
      if (this.keyboard.pressed("i")) {
        this.controls.setMode("scale");
      }

      // W键:视角前进。
      if (this.keyboard.pressed("w")) {
        this.person.translateZ(-moveDistance);
        this.mainCamera.translateZ(-moveDistance);
      }
      // S键:视角后退。
      if (this.keyboard.pressed("s")) {
        this.person.translateZ(moveDistance);
        this.mainCamera.translateZ(moveDistance);
      }
      // A键:视角左移。
      if (this.keyboard.pressed("a")) {
        this.person.translateX(-moveDistance);
        this.mainCamera.translateX(-moveDistance);
      }
      // D键:视角右移。
      if (this.keyboard.pressed("d")) {
        this.person.translateX(moveDistance);
        this.mainCamera.translateX(moveDistance);
      }
      // Q键:视角上升。
      if (this.keyboard.pressed("q")) {
        this.person.translateY(moveDistance);
        this.mainCamera.translateY(moveDistance);
      }
      // E键:视角下降。
      if (this.keyboard.pressed("e")) {
        this.person.translateY(-moveDistance);
        this.mainCamera.translateY(-moveDistance);
      }
