    // 屏幕坐标转世界坐标
    positionScreenToWorld: function (x, y) {
      // 屏幕坐标转标准设备坐标
      const x1 = (x / window.innerWidth) * 2 - 1;
      const y1 = -(y / window.innerHeight) * 2 + 1;
      //标准设备坐标(z = 0.5这个值并没有一个具体的说法)
      const stdVector = new THREE.Vector3(x1, y1, 0.5);
      // 标准设备坐标转世界坐标
      return stdVector.unproject(this.mainCamera);
    },
    // 世界坐标转屏幕坐标
    positionWorldToScreen: function (worldVector) {
      const centerX = this.windowSizes.width / 2;
      const centerY = this.windowSizes.height / 2;
      const standardVec = worldVector.project(this.mainCamera);

      const screenPosition = {};
      screenPosition.x = Math.round(centerX * standardVec.x + centerX);
      screenPosition.y = Math.round(-centerY * standardVec.y + centerY);
      return screenPosition;
