    // 删除group，释放内存
    removeMeshGroup: function (group) {
      if (!group) return;
      // 循环删除掉所有的模型组内的mesh
      group.traverse(function (item) {
        if (item instanceof THREE.Mesh) {
          if (item.geometry instanceof Array) {
            item.material.forEach(geome => {
              // 删除几何体
              geome.dispose();
            });
          } else {
            // 删除几何体
            item.geometry.dispose();
          }
          if (item.material instanceof Array) {
            item.material.forEach(meta => {
              // 删除材质
              meta.dispose();
            });
          } else {
            // 删除材质
            item.material.dispose();
          }
        }
      });
