      group.removeFromParent();

      // 从控制器中移除当前3D对象，并确保控制器UI是不可见的。
      this.controls.detach();

      // 删除节点数据
      delete this.graphSpace.nodes[group.nodeId];

      // 删除模型缓存数据
      const new_set = new Set(this.graphSpace.meshGroups);
      new_set.delete(group);
      this.graphSpace.meshGroups = [...new_set];
